import type { Feature, FeatureCollection } from 'geojson';

import { INCLUDE_ALL_WILDCARD_RULE } from '../constants.js';
import type { BaseLayerRules } from '../types/base-layer.js';

export const applyFeatureFilterRules =
  (rules: BaseLayerRules, regionPrefix?: string) =>
  (value: FeatureCollection) => {
    const { include, exclude } = rules;

    let filteredFeatures: Feature[] = value.features;

    const includeAllRule = regionPrefix
      ? `${regionPrefix}-${INCLUDE_ALL_WILDCARD_RULE}`
      : INCLUDE_ALL_WILDCARD_RULE;

    if (!include.includes(includeAllRule) && include.length > 0) {
      filteredFeatures = filteredFeatures.filter((feature) =>
        include.includes(feature.id as string),
      );
    }

    if (exclude.length > 0) {
      filteredFeatures = filteredFeatures.filter(
        (feature) => !exclude.includes(feature.id as string),
      );
    }

    return { ...value, features: filteredFeatures };
  };
